/* ═══════════════════════════════════════════════════════════════════════════
   PWA Install Prompt — "Add to Home Screen" banner
   Shows on mobile browsers after 5s delay when the beforeinstallprompt fires.
   Persists dismissal in localStorage so user only sees it once.
   ═══════════════════════════════════════════════════════════════════════════ */
import { useState, useEffect } from 'react';

export default function PWAInstallPrompt() {
  const [deferredPrompt, setDeferredPrompt] = useState(null);
  const [show, setShow] = useState(false);

  useEffect(() => {
    // Skip if already in standalone / installed mode
    if (window.matchMedia('(display-mode: standalone)').matches) return;
    if (window.navigator.standalone === true) return;

    const handler = (e) => {
      e.preventDefault();
      setDeferredPrompt(e);
      // Only show if not dismissed before
      if (!localStorage.getItem('aura_pwa_dismissed')) {
        // Track visits — show after 2nd visit for better conversion
        const visits = parseInt(localStorage.getItem('aura_pwa_visits') || '0', 10) + 1;
        localStorage.setItem('aura_pwa_visits', String(visits));
        if (visits >= 2) {
          setTimeout(() => setShow(true), 5000);
        }
      }
    };
    window.addEventListener('beforeinstallprompt', handler);
    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  const handleInstall = async () => {
    if (!deferredPrompt) return;
    deferredPrompt.prompt();
    const result = await deferredPrompt.userChoice;
    setDeferredPrompt(null);
    setShow(false);
    localStorage.setItem('aura_pwa_dismissed', '1');
  };

  const handleDismiss = () => {
    setShow(false);
    localStorage.setItem('aura_pwa_dismissed', '1');
  };

  if (!show) return null;

  return (
    <div style={{
      position: 'fixed',
      bottom: 0,
      left: 0,
      right: 0,
      zIndex: 9998,
      background: '#161B22',
      borderTop: '1px solid rgba(63,185,80,0.2)',
      padding: '16px 20px',
      fontFamily: "'Plus Jakarta Sans', system-ui, sans-serif",
      display: 'flex',
      alignItems: 'center',
      gap: 12,
      boxShadow: '0 -4px 24px rgba(0,0,0,0.4)',
      backdropFilter: 'blur(12px)',
    }}>
      {/* App icon */}
      <img
        src="/images/icon-192.png"
        alt=""
        width={40}
        height={40}
        style={{ borderRadius: 10, flexShrink: 0 }}
        onError={(e) => { e.target.style.display = 'none'; }}
      />
      {/* Text */}
      <div style={{ flex: 1, minWidth: 0 }}>
        <div style={{
          color: '#E6EDF3',
          fontSize: 15,
          fontWeight: 600,
          marginBottom: 2,
          whiteSpace: 'nowrap',
          overflow: 'hidden',
          textOverflow: 'ellipsis',
        }}>
          Add Aura Alpha to your home screen
        </div>
        <div style={{ color: '#8B949E', fontSize: 13 }}>
          Instant launch, offline access, app-like experience
        </div>
      </div>
      {/* Install button */}
      <button
        onClick={handleInstall}
        style={{
          background: '#3FB950',
          color: '#0D1117',
          border: 'none',
          borderRadius: 8,
          padding: '8px 20px',
          fontSize: 14,
          fontWeight: 600,
          cursor: 'pointer',
          fontFamily: 'inherit',
          whiteSpace: 'nowrap',
          flexShrink: 0,
        }}
      >
        Install
      </button>
      {/* Dismiss button */}
      <button
        onClick={handleDismiss}
        style={{
          background: 'transparent',
          color: '#8B949E',
          border: 'none',
          padding: '8px 8px',
          fontSize: 13,
          cursor: 'pointer',
          fontFamily: 'inherit',
          whiteSpace: 'nowrap',
          flexShrink: 0,
        }}
      >
        Not now
      </button>
    </div>
  );
}
